-- Migration: Ensure system administrator has correct role assignment&#10;-- Date: 2026-03-19&#10;&#10;DO $$$$&#10;DECLARE&#10;  admin_user_id UUID;&#10;  admin_role_id UUID;&#10;BEGIN&#10;  SELECT id INTO admin_user_id FROM auth.users WHERE email = 'admin@glrsdac.com';&#10;  SELECT id INTO admin_role_id FROM public.roles WHERE name = 'superadmin';&#10;  IF admin_user_id IS NOT NULL AND admin_role_id IS NOT NULL THEN&#10;    INSERT INTO public.user_roles (id, user_id, role_id, assigned_at)&#10;    VALUES (gen_random_uuid(), admin_user_id, admin_role_id, NOW())&#10;    ON CONFLICT (user_id, role_id) DO NOTHING;&#10;  END IF;&#10;END $$$$;
